import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter your name:");
        String name = scanner.nextLine();

        int maxLength = 10; // Maximum length for the buffer
        char[] buffer = new char[maxLength];

        // Limit the number of characters copied to prevent buffer overflow
        int copyLength = Math.min(name.length(), maxLength);
        name.getChars(0, copyLength, buffer, 0);

        // Print out the contents of the buffer for demonstration
        System.out.println("Buffer content: " + new String(buffer));
    }
}

